// src/components/Navbar.jsx
import React, { useState, useEffect } from 'react';
import { Navbar, Nav, Container, NavDropdown, Form, Button, Modal } from 'react-bootstrap';
import { Link, useLocation } from 'react-router-dom';
import { 
  FaHome, FaInfoCircle, FaProjectDiagram, 
  FaEnvelope, FaPhone, FaTimes, FaPaperPlane,
  FaFacebook, FaTwitter, FaInstagram, FaLinkedin,
  FaImages // Gallery icon
} from 'react-icons/fa';
import logo from '../assets/logo.png';

const Navigation = () => {
  // ... existing state and hooks remain unchanged ...

  return (
    <>
      <Navbar 
        expand="lg" 
        bg="dark" 
        variant="dark" 
        sticky="top" 
        className={`custom-navbar ${scrolled ? 'scrolled' : ''}`}
        expanded={expanded}
        onToggle={() => setExpanded(!expanded)}
      >
        <Container fluid className="px-4">
          <Navbar.Brand as={Link} to="/" className="fw-bold d-flex align-items-center">
            <div className="brand-logo">
              <img 
                src={logo} 
                alt="BUKANI MAMA TOTO Logo" 
                className="logo-image"
              />
              <div className="wave-effect"></div>
            </div>
            <div className="brand-text ms-3">
              <div className="brand-title">BUKANI MAMA TOTO</div>
              <div className="brand-subtitle">Empowering Women • Blue Economy</div>
            </div>
          </Navbar.Brand>
          
          <Navbar.Toggle aria-controls="main-nav" className="border-0">
            <div className={`hamburger ${expanded ? 'open' : ''}`}>
              <span></span>
              <span></span>
              <span></span>
            </div>
          </Navbar.Toggle>
          
          <Navbar.Collapse id="main-nav">
            <Nav className="ms-auto align-items-lg-center">
              <Nav.Link as={Link} to="/" className="nav-link">
                <FaHome className="me-1" /> Home
              </Nav.Link>
              <Nav.Link as={Link} to="/about" className="nav-link">
                <FaInfoCircle className="me-1" /> About
              </Nav.Link>
              
              <NavDropdown 
                title={
                  <span>
                    <FaProjectDiagram className="me-1" /> Initiatives
                  </span>
                } 
                id="nav-initiatives"
                className="nav-dropdown"
              >
                <NavDropdown.Item as={Link} to="/initiatives/fish-farming" className="dropdown-item">
                  Fish Farming
                </NavDropdown.Item>
                <NavDropdown.Item as={Link} to="/initiatives/table-banking" className="dropdown-item">
                  Table Banking
                </NavDropdown.Item>
                <NavDropdown.Item as={Link} to="/initiatives/conservation" className="dropdown-item">
                  Conservation
                </NavDropdown.Item>
              </NavDropdown>

              {/* Gallery Button - Fixed with responsive adjustments */}
              <Nav.Link as={Link} to="/gallery" className="nav-link gallery-link">
                <FaImages className="me-1" /> Gallery
              </Nav.Link>
              
              <Nav.Link 
                className="nav-link contact-link" 
                onClick={handleContactClick}
              >
                <FaEnvelope className="me-1" /> Contact
              </Nav.Link>
              
              <div className="d-lg-none mt-3">
                <div className="social-icons d-flex justify-content-center gap-3">
                  <a href="https://facebook.com" target="_blank" rel="noopener noreferrer" className="social-icon">
                    <FaFacebook />
                  </a>
                  <a href="https://twitter.com" target="_blank" rel="noopener noreferrer" className="social-icon">
                    <FaTwitter />
                  </a>
                  <a href="https://instagram.com" target="_blank" rel="noopener noreferrer" className="social-icon">
                    <FaInstagram />
                  </a>
                  <a href="https://linkedin.com" target="_blank" rel="noopener noreferrer" className="social-icon">
                    <FaLinkedin />
                  </a>
                </div>
              </div>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      {/* Contact Modal remains unchanged */}

      {/* Updated Custom CSS with fixes for gallery button */}
      <style jsx>{`
        .custom-navbar {
          background: linear-gradient(135deg, #0a1929 0%, #1a2a3a 100%);
          padding: 0.8rem 0;
          border-bottom: 1px solid rgba(255, 255, 255, 0.1);
          transition: all 0.3s ease;
        }
        
        .custom-navbar.scrolled {
          padding: 0.5rem 0;
          box-shadow: 0 5px 20px rgba(0, 0, 0, 0.2);
          background: rgba(10, 25, 41, 0.95);
          backdrop-filter: blur(10px);
        }
        
        .brand-logo {
          position: relative;
          width: 60px;
          height: 60px;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          overflow: hidden;
        }
        
        .logo-image {
          width: 100%;
          height: 100%;
          object-fit: contain;
          z-index: 2;
          position: relative;
        }
        
        .wave-effect {
          position: absolute;
          bottom: 0;
          left: 0;
          width: 100%;
          height: 30%;
          background: rgba(26, 147, 111, 0.3);
          border-radius: 50% 50% 0 0;
